namespace ConfettiApp
{
    public static class AppStore
    {
        public static int Count = 600;
        public static float Density = 3.0f, Gravity = 0.39f, Speed = 25f, Spread = 1f, Wobble = 5.0f, Size = 1f, Duration = 1.1f;
        public static string Origin = "center";
        public static string ConfigDirectoryPath { get { return Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "config"); } }
        public static string ConfigFilePath { get { return Path.Combine(ConfigDirectoryPath, "confetti-settings.ini"); } }
        public static string ReadmeFilePath { get { return Path.Combine(ConfigDirectoryPath, "README.txt"); } }
        static string LegacyPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "confetti_config.dat");

        static float Clamp(float value, float min, float max) { return Math.Max(min, Math.Min(max, value)); }
        static int Clamp(int value, int min, int max) { return Math.Max(min, Math.Min(max, value)); }
        static void Normalize() {
            Count = Clamp(Count, 50, 600);
            Density = Clamp(Density, 0.10f, 3.00f);
            Gravity = Clamp(Gravity, 0.00f, 2.00f);
            Speed = Clamp(Speed, 5.0f, 40.0f);
            Spread = Clamp(Spread, 0.10f, 3.00f);
            Wobble = Clamp(Wobble, 0.0f, 5.0f);
            Size = Clamp(Size, 0.10f, 3.00f);
            Duration = Clamp(Duration, 0.1f, 6.0f);
            if (Origin != "sides" && Origin != "top" && Origin != "center") Origin = "sides";
        }

        static void EnsureConfigDirectory()
        {
            if (!Directory.Exists(ConfigDirectoryPath)) Directory.CreateDirectory(ConfigDirectoryPath);
        }

        static void TryMigrateLegacyConfig()
        {
            try {
                if (!File.Exists(LegacyPath) || File.Exists(ConfigFilePath)) return;
                var p = File.ReadAllText(LegacyPath).Split('|');
                Count = int.Parse(p[0], CultureInfo.InvariantCulture);
                Density = float.Parse(p[1], CultureInfo.InvariantCulture);
                Gravity = float.Parse(p[2], CultureInfo.InvariantCulture);
                Speed = float.Parse(p[3], CultureInfo.InvariantCulture);
                Spread = float.Parse(p[4], CultureInfo.InvariantCulture);
                Wobble = float.Parse(p[5], CultureInfo.InvariantCulture);
                Size = float.Parse(p[6], CultureInfo.InvariantCulture);
                Origin = p[7];
                if (p.Length > 8) Duration = float.Parse(p[8], CultureInfo.InvariantCulture);
                Normalize();
                Save();
                File.Delete(LegacyPath);
            } catch {}
        }

        static Dictionary<string, string> ReadConfigValues()
        {
            var values = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            if (!File.Exists(ConfigFilePath)) return values;

            foreach (string rawLine in File.ReadAllLines(ConfigFilePath)) {
                string line = rawLine.Trim();
                if (line.Length == 0 || line.StartsWith("#") || line.StartsWith(";") || (line.StartsWith("[") && line.EndsWith("]"))) continue;
                int split = line.IndexOf('=');
                if (split <= 0) continue;
                string key = line.Substring(0, split).Trim();
                string value = line.Substring(split + 1).Trim();
                values[key] = value;
            }
            return values;
        }

        static float ParseFloat(Dictionary<string, string> values, string key, float fallback)
        {
            float parsed;
            return values.ContainsKey(key) && float.TryParse(values[key], NumberStyles.Float, CultureInfo.InvariantCulture, out parsed) ? parsed : fallback;
        }

        static int ParseInt(Dictionary<string, string> values, string key, int fallback)
        {
            int parsed;
            return values.ContainsKey(key) && int.TryParse(values[key], NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) ? parsed : fallback;
        }

        static bool ParseBool(Dictionary<string, string> values, string key, bool fallback)
        {
            if (!values.ContainsKey(key)) return fallback;
            string value = values[key];
            if (string.Equals(value, "true", StringComparison.OrdinalIgnoreCase) || value == "1" || string.Equals(value, "yes", StringComparison.OrdinalIgnoreCase) || string.Equals(value, "on", StringComparison.OrdinalIgnoreCase)) return true;
            if (string.Equals(value, "false", StringComparison.OrdinalIgnoreCase) || value == "0" || string.Equals(value, "no", StringComparison.OrdinalIgnoreCase) || string.Equals(value, "off", StringComparison.OrdinalIgnoreCase)) return false;
            return fallback;
        }

        static void WriteReadme()
        {
            try {
                File.WriteAllText(ReadmeFilePath,
@"Confetti config folder
=====================

Files here:
- confetti-settings.ini : main settings file for the app
- README.txt            : this quick guide

How to edit:
1. Open confetti-settings.ini in Notepad.
2. Change the value after the = sign.
3. Save the file.
4. The app reloads the file automatically a moment later.

Notes:
- Keep values inside the listed ranges.
- origin can be: sides, top, center
- start_on_windows can be: true or false
- Lines starting with # are comments.");
            } catch {}
        }

        public static void Load() {
            try {
                EnsureConfigDirectory();
                TryMigrateLegacyConfig();
                if (!File.Exists(ConfigFilePath)) {
                    Save();
                    WriteReadme();
                }

                var values = ReadConfigValues();
                Count = ParseInt(values, "count", Count);
                Density = ParseFloat(values, "density", Density);
                Gravity = ParseFloat(values, "gravity", Gravity);
                Speed = ParseFloat(values, "speed", Speed);
                Spread = ParseFloat(values, "spread", Spread);
                Wobble = ParseFloat(values, "wobble", Wobble);
                Size = ParseFloat(values, "size", Size);
                Duration = ParseFloat(values, "duration", Duration);
                if (values.ContainsKey("origin")) Origin = values["origin"];
                SetStartup(ParseBool(values, "start_on_windows", IsStartupEnabled()));
            } catch {}
            Normalize();
        }
        public static void Save() {
            try {
                EnsureConfigDirectory();
                Normalize();
                File.WriteAllText(ConfigFilePath,
string.Join(Environment.NewLine, new string[] {
    "# Confetti settings",
    "# Edit the values, save the file, and the app reloads them automatically.",
    "",
    "[effect]",
    "# count: total particles per burst (50 to 600)",
    "count = " + Count.ToString(CultureInfo.InvariantCulture),
    "# density: width/spread of the burst source (0.10 to 3.00)",
    "density = " + Density.ToString("0.00", CultureInfo.InvariantCulture),
    "# gravity: downward pull on particles (0.00 to 2.00)",
    "gravity = " + Gravity.ToString("0.00", CultureInfo.InvariantCulture),
    "# speed: launch speed of particles (5 to 40)",
    "speed = " + Speed.ToString("0.##", CultureInfo.InvariantCulture),
    "# spread: horizontal spread multiplier (0.10 to 3.00)",
    "spread = " + Spread.ToString("0.00", CultureInfo.InvariantCulture),
    "# wobble: side-to-side motion amount (0.0 to 5.0)",
    "wobble = " + Wobble.ToString("0.0#", CultureInfo.InvariantCulture),
    "# size: particle size multiplier (0.10 to 3.00)",
    "size = " + Size.ToString("0.00", CultureInfo.InvariantCulture),
    "# duration: how long one burst emits particles in seconds (0.1 to 6.0)",
    "duration = " + Duration.ToString("0.0#", CultureInfo.InvariantCulture),
    "# origin: sides, top, or center",
    "origin = " + Origin,
    "",
    "[startup]",
    "# start_on_windows: true or false",
    "start_on_windows = " + (IsStartupEnabled() ? "true" : "false")
}));
                WriteReadme();
                if (File.Exists(LegacyPath)) File.Delete(LegacyPath);
            } catch {}
        }
        public static void Reset() {
            Count = 600; Density = 3.0f; Gravity = 0.39f; Speed = 25f; Spread = 1f; Wobble = 5.0f; Size = 1f; Duration = 1.1f; Origin = "center";
            Save();
        }
        public static bool IsStartupEnabled() {
            try {
                using(RegistryKey rk = Registry.CurrentUser.OpenSubKey(@"SOFTWARE\Microsoft\Windows\CurrentVersion\Run", false)) {
                    return rk.GetValue("ConfettiApp") != null;
                }
            } catch { return false; }
        }
        public static void SetStartup(bool enable) {
            try {
                using(RegistryKey rk = Registry.CurrentUser.OpenSubKey(@"SOFTWARE\Microsoft\Windows\CurrentVersion\Run", true)) {
                    if (enable) rk.SetValue("ConfettiApp", Application.ExecutablePath);
                    else rk.DeleteValue("ConfettiApp", false);
                }
            } catch {}
        }
    }

    public class SettingsSnapshot
    {
        public int Count;
        public float Density, Gravity, Speed, Spread, Wobble, Size, Duration;
        public string Origin;

        public static SettingsSnapshot Capture()
        {
            return new SettingsSnapshot {
                Count = AppStore.Count,
                Density = AppStore.Density,
                Gravity = AppStore.Gravity,
                Speed = AppStore.Speed,
                Spread = AppStore.Spread,
                Wobble = AppStore.Wobble,
                Size = AppStore.Size,
                Duration = AppStore.Duration,
                Origin = AppStore.Origin
            };
        }
    }

    public class Particle
    {
        public float X, Y, VX, VY, Angle, Spin, W, H, Tick, WFreq;
        public int ColorIndex;
        static Random R = new Random();
        static Color[] Palette = { Color.FromArgb(167,139,250), Color.FromArgb(244,114,182), Color.FromArgb(251,146,60), Color.FromArgb(52,211,153), Color.FromArgb(96,165,250), Color.White };
        public static readonly Brush[] Brushes = Palette.Select(c => new SolidBrush(c)).Cast<Brush>().ToArray();

        public Particle(int sw, int sh)
        {
            WFreq = (float)(R.NextDouble()*0.1+0.1); Tick = (float)(R.NextDouble()*6.28);
            if (AppStore.Origin == "top") { X = (float)(sw/2+(R.NextDouble()-0.5)*sw*AppStore.Density); Y = -50; VX = (float)(R.NextDouble()*10-5)*AppStore.Spread; VY = (float)(R.NextDouble()*5+3.0f); }
            else if (AppStore.Origin == "center") { X = sw/2f; Y = sh/2f; double a = R.NextDouble()*6.28; float m = (float)(R.NextDouble()*AppStore.Speed*0.8+AppStore.Speed*0.4); VX = (float)Math.Cos(a)*m*AppStore.Spread; VY = (float)Math.Sin(a)*m; }
            else { bool left = R.NextDouble()<0.5; X = left?-20:sw+20; Y = sh+20; double a = (left?-70:-110)*Math.PI/180+(R.NextDouble()-0.5)*0.4*AppStore.Density; float m = (float)(R.NextDouble()*AppStore.Speed*0.7+AppStore.Speed*0.9); VX=(float)Math.Cos(a)*m*AppStore.Spread; VY=(float)Math.Sin(a)*m; }
            Spin = (float)(R.NextDouble()*30-15); W = (float)(R.NextDouble()*12+8)*AppStore.Size; H = W*0.6f; 
            ColorIndex = R.Next(Palette.Length);
        }
        public bool Update(float g, float w, int sh) { Tick += WFreq; VY += g; VX *= 0.99f; VY *= 0.99f; X += VX + (float)Math.Sin(Tick)*w; Y += VY; Angle += Spin; return Y < sh + 100 && !(Y < -500 && VY < 0); }

        public void ApplySettingsDelta(SettingsSnapshot before, SettingsSnapshot after)
        {
            if (before == null || after == null) return;

            if (before.Size > 0.001f && Math.Abs(after.Size - before.Size) > 0.001f) {
                float sizeRatio = after.Size / before.Size;
                W *= sizeRatio;
                H *= sizeRatio;
            }

        }
    }

    public class SettingsForm : Form
    {
        readonly Panel body = new Panel();
        readonly Label statusLabel = new Label();
        readonly CheckBox startupCheck = new CheckBox();
        readonly ComboBox originBox = new ComboBox();
        readonly TrackBar countSlider = new TrackBar();
        readonly TrackBar densitySlider = new TrackBar();
        readonly TrackBar gravitySlider = new TrackBar();
        readonly TrackBar speedSlider = new TrackBar();
        readonly TrackBar spreadSlider = new TrackBar();
        readonly TrackBar wobbleSlider = new TrackBar();
        readonly TrackBar sizeSlider = new TrackBar();
        readonly TrackBar durationSlider = new TrackBar();
        readonly Label countValue = new Label();
        readonly Label densityValue = new Label();
        readonly Label gravityValue = new Label();
        readonly Label speedValue = new Label();
        readonly Label spreadValue = new Label();
        readonly Label wobbleValue = new Label();
        readonly Label sizeValue = new Label();
        readonly Label durationValue = new Label();
        readonly List<TrackBar> sliders = new List<TrackBar>();
        bool syncing;
        public event Action<SettingsSnapshot, SettingsSnapshot> SettingsApplied;

        public SettingsForm()
        {
            Text = "Confetti Settings";
            StartPosition = FormStartPosition.CenterScreen;
            FormBorderStyle = FormBorderStyle.FixedDialog;
            MaximizeBox = false;
            MinimizeBox = false;
            ShowInTaskbar = false;
            ClientSize = new Size(520, 620);
            BackColor = Color.FromArgb(18, 22, 31);
            ForeColor = Color.FromArgb(236, 239, 244);
            Font = new Font("Segoe UI", 9F);

            body.Dock = DockStyle.Fill;
            body.Padding = new Padding(18, 16, 18, 16);
            body.BackColor = BackColor;
            Controls.Add(body);

            var title = new Label {
                Text = "Settings",
                Font = new Font("Segoe UI Semibold", 14F),
                AutoSize = true,
                Location = new Point(18, 12),
                ForeColor = ForeColor
            };
            body.Controls.Add(title);

            var subtitle = new Label {
                Text = "Live changes apply instantly to the active effect.",
                AutoSize = true,
                ForeColor = Color.FromArgb(138, 149, 173),
                Location = new Point(18, 41)
            };
            body.Controls.Add(subtitle);

            startupCheck.AutoSize = true;
            startupCheck.Text = "Start on Windows";
            startupCheck.ForeColor = ForeColor;
            startupCheck.BackColor = BackColor;
            startupCheck.CheckedChanged += delegate { if (!syncing) ApplyFromControls(); };
            body.Controls.Add(startupCheck);

            var settingsGroup = CreateGroup("Live Settings", new Point(18, 86), new Size(484, 462));
            body.Controls.Add(settingsGroup);

            var settingsGrid = CreateGrid(settingsGroup, 9);

            ConfigureSlider(countSlider, 50, 600, countValue, 1f, false);
            ConfigureSlider(densitySlider, 10, 300, densityValue, 100f, true);
            ConfigureSlider(durationSlider, 1, 60, durationValue, 10f, true);
            ConfigureSlider(speedSlider, 5, 40, speedValue, 1f, false);
            ConfigureSlider(gravitySlider, 0, 200, gravityValue, 100f, true);
            ConfigureSlider(spreadSlider, 10, 300, spreadValue, 100f, true);
            ConfigureSlider(wobbleSlider, 0, 50, wobbleValue, 10f, true);
            ConfigureSlider(sizeSlider, 10, 300, sizeValue, 100f, true);
            sliders.AddRange(new TrackBar[] { countSlider, densitySlider, durationSlider, speedSlider, gravitySlider, spreadSlider, wobbleSlider, sizeSlider });
            foreach (TrackBar slider in sliders) {
                slider.ValueChanged += delegate { if (!syncing) ApplyFromControls(); };
            }

            originBox.DropDownStyle = ComboBoxStyle.DropDownList;
            originBox.Items.AddRange(new object[] { "sides", "top", "center" });
            originBox.Anchor = AnchorStyles.Left | AnchorStyles.Right;
            originBox.BackColor = Color.FromArgb(37, 44, 61);
            originBox.ForeColor = Color.FromArgb(236, 239, 244);

            AddSliderRow(settingsGrid, 0, "Count", countSlider, countValue);
            AddSliderRow(settingsGrid, 1, "Density", densitySlider, densityValue);
            AddSliderRow(settingsGrid, 2, "Duration", durationSlider, durationValue);
            AddSliderRow(settingsGrid, 3, "Speed", speedSlider, speedValue);
            AddSliderRow(settingsGrid, 4, "Gravity", gravitySlider, gravityValue);
            AddSliderRow(settingsGrid, 5, "Spread", spreadSlider, spreadValue);
            AddSliderRow(settingsGrid, 6, "Wobble", wobbleSlider, wobbleValue);
            AddSliderRow(settingsGrid, 7, "Size", sizeSlider, sizeValue);
            AddRow(settingsGrid, 8, "Origin", originBox);

            statusLabel.Text = "Live mode is always on. Changes apply instantly.";
            statusLabel.AutoSize = true;
            statusLabel.ForeColor = Color.FromArgb(138, 149, 173);
            statusLabel.Location = new Point(18, 560);
            body.Controls.Add(statusLabel);

            var resetButton = new Button {
                Text = "Reset",
                Size = new Size(92, 34),
                Location = new Point(18, 582)
            };
            resetButton.Click += delegate {
                AppStore.Reset();
                RefreshUI();
                if (!syncing) ApplyFromControls();
            };
            body.Controls.Add(resetButton);

            var closeButton = new Button {
                Text = "Close",
                Size = new Size(92, 34),
                Location = new Point(410, 582)
            };
            closeButton.Click += delegate { Hide(); };
            body.Controls.Add(closeButton);

            Resize += delegate { CenterStartupCheckBox(); };
            Shown += delegate { RefreshUI(); };
            FormClosing += delegate(object sender, FormClosingEventArgs e) {
                e.Cancel = true;
                Hide();
            };

            RefreshUI();
            CenterStartupCheckBox();
        }

        static GroupBox CreateGroup(string text, Point location, Size size)
        {
            var box = new GroupBox();
            box.Text = text;
            box.Location = location;
            box.Size = size;
            box.BackColor = Color.FromArgb(28, 34, 48);
            box.ForeColor = Color.FromArgb(236, 239, 244);
            return box;
        }

        static TableLayoutPanel CreateGrid(Control parent)
        {
            return CreateGrid(parent, 5);
        }

        static TableLayoutPanel CreateGrid(Control parent, int rows)
        {
            var grid = new TableLayoutPanel();
            grid.Location = new Point(10, 22);
            grid.Size = new Size(parent.Width - 20, parent.Height - 30);
            grid.ColumnCount = 2;
            grid.RowCount = rows;
            grid.BackColor = parent.BackColor;
            grid.ColumnStyles.Add(new ColumnStyle(SizeType.Absolute, 70F));
            grid.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 100F));
            for (int i = 0; i < rows; i++) grid.RowStyles.Add(new RowStyle(SizeType.Absolute, 52F));
            parent.Controls.Add(grid);
            return grid;
        }

        static void ConfigureSlider(TrackBar slider, int min, int max, Label valueLabel, float scale, bool showDecimals)
        {
            slider.Minimum = min;
            slider.Maximum = max;
            slider.TickStyle = TickStyle.None;
            slider.AutoSize = false;
            slider.Height = 24;
            slider.Width = 124;
            slider.BackColor = Color.FromArgb(37, 44, 61);
            slider.Margin = new Padding(0, 0, 6, 0);

            valueLabel.AutoSize = false;
            valueLabel.Width = 72;
            valueLabel.TextAlign = ContentAlignment.MiddleRight;
            valueLabel.ForeColor = Color.FromArgb(113, 183, 255);
            valueLabel.BackColor = Color.FromArgb(24, 29, 41);
            valueLabel.BorderStyle = BorderStyle.FixedSingle;
            valueLabel.Font = new Font("Segoe UI Semibold", 8.5F);
            valueLabel.Padding = new Padding(0, 2, 4, 0);

            slider.ValueChanged += delegate {
                float display = slider.Value / scale;
                valueLabel.Text = showDecimals ? display.ToString("0.0#") : display.ToString("0");
                if (!slider.IsHandleCreated) return;
            };
        }

        static void AddRow(TableLayoutPanel grid, int row, string labelText, Control control)
        {
            var label = new Label { Text = labelText, AutoSize = true, Anchor = AnchorStyles.Left, Margin = new Padding(3, 6, 3, 3), ForeColor = Color.FromArgb(216, 221, 230), BackColor = grid.BackColor };
            control.Margin = new Padding(3, 2, 3, 2);
            control.Width = 150;
            if (control is ComboBox) {
                control.BackColor = Color.FromArgb(37, 44, 61);
                control.ForeColor = Color.FromArgb(236, 239, 244);
                ((ComboBox)control).FlatStyle = FlatStyle.Flat;
            }
            grid.Controls.Add(label, 0, row);
            grid.Controls.Add(control, 1, row);
        }

        static void AddSliderRow(TableLayoutPanel grid, int row, string labelText, TrackBar slider, Label valueLabel)
        {
            var host = new FlowLayoutPanel();
            host.FlowDirection = FlowDirection.LeftToRight;
            host.WrapContents = false;
            host.AutoSize = true;
            host.BackColor = grid.BackColor;
            host.Margin = new Padding(0);
            host.Padding = new Padding(0, 6, 0, 0);
            host.Controls.Add(slider);
            host.Controls.Add(valueLabel);
            AddRow(grid, row, labelText, host);
        }

        void CenterStartupCheckBox()
        {
            startupCheck.Location = new Point(Math.Max(18, (body.ClientSize.Width - startupCheck.Width) / 2), 62);
        }

        void ApplyFromControls()
        {
            if (syncing) return;

            var previous = SettingsSnapshot.Capture();
            AppStore.Count = countSlider.Value;
            AppStore.Density = densitySlider.Value / 100f;
            AppStore.Gravity = gravitySlider.Value / 100f;
            AppStore.Speed = speedSlider.Value;
            AppStore.Spread = spreadSlider.Value / 100f;
            AppStore.Wobble = wobbleSlider.Value / 10f;
            AppStore.Size = sizeSlider.Value / 100f;
            AppStore.Duration = durationSlider.Value / 10f;
            AppStore.Origin = Convert.ToString(originBox.SelectedItem ?? "sides");
            AppStore.SetStartup(startupCheck.Checked);
            AppStore.Save();
            RaiseSettingsApplied(previous, SettingsSnapshot.Capture());
        }

        void RaiseSettingsApplied(SettingsSnapshot previous, SettingsSnapshot current)
        {
            statusLabel.Text = "Live-applied at " + DateTime.Now.ToString("h:mm:ss tt");
            if (SettingsApplied != null) SettingsApplied(previous, current);
        }

        public void RefreshUI()
        {
            syncing = true;
            countSlider.Value = ClampInt(AppStore.Count, countSlider);
            densitySlider.Value = ClampInt((int)Math.Round(AppStore.Density * 100), densitySlider);
            gravitySlider.Value = ClampInt((int)Math.Round(AppStore.Gravity * 100), gravitySlider);
            speedSlider.Value = ClampInt((int)Math.Round(AppStore.Speed), speedSlider);
            spreadSlider.Value = ClampInt((int)Math.Round(AppStore.Spread * 100), spreadSlider);
            wobbleSlider.Value = ClampInt((int)Math.Round(AppStore.Wobble * 10), wobbleSlider);
            sizeSlider.Value = ClampInt((int)Math.Round(AppStore.Size * 100), sizeSlider);
            durationSlider.Value = ClampInt((int)Math.Round(AppStore.Duration * 10), durationSlider);
            originBox.SelectedItem = originBox.Items.Contains(AppStore.Origin) ? AppStore.Origin : "sides";
            startupCheck.Checked = AppStore.IsStartupEnabled();
            countValue.Text = countSlider.Value.ToString("0");
            densityValue.Text = (densitySlider.Value / 100f).ToString("0.0#");
            gravityValue.Text = (gravitySlider.Value / 100f).ToString("0.0#");
            speedValue.Text = speedSlider.Value.ToString("0");
            spreadValue.Text = (spreadSlider.Value / 100f).ToString("0.0#");
            wobbleValue.Text = (wobbleSlider.Value / 10f).ToString("0.0#");
            sizeValue.Text = (sizeSlider.Value / 100f).ToString("0.0#");
            durationValue.Text = (durationSlider.Value / 10f).ToString("0.0#");
            statusLabel.Text = "Live mode is always on. Changes apply instantly.";
            CenterStartupCheckBox();
        }

        static int ClampInt(int value, TrackBar input)
        {
            if (value < input.Minimum) return input.Minimum;
            if (value > input.Maximum) return input.Maximum;
            return value;
        }

        public void Toggle()
        {
            if (Visible) Hide();
            else {
                RefreshUI();
                Show();
                Activate();
            }
        }
    }

    public class ConfettiMain : Form
    {
        [DllImport("user32.dll")] static extern bool RegisterHotKey(IntPtr h, int id, uint mod, int vk);
        [DllImport("user32.dll")] static extern int GetWindowLong(IntPtr h, int i);
        [DllImport("user32.dll")] static extern int SetWindowLong(IntPtr h, int i, int v);
        [DllImport("user32.dll")] static extern bool DestroyIcon(IntPtr handle);
        List<Particle> parts = new List<Particle>();
        System.Windows.Forms.Timer timer = new System.Windows.Forms.Timer { Interval = 16 };
        System.Windows.Forms.Timer configReloadTimer = new System.Windows.Forms.Timer { Interval = 350 };
        FileSystemWatcher configWatcher;
        MenuItem startupMenuItem;
        NotifyIcon tray;
        float pendingSpawns = 0; DateTime lastFire = DateTime.MinValue;
        Icon appIcon;

        public ConfettiMain()
        {
            FormBorderStyle = FormBorderStyle.None; Bounds = Screen.PrimaryScreen.Bounds; TopMost = true; ShowInTaskbar = false;
            BackColor = Color.Black; TransparencyKey = Color.Black; DoubleBuffered = true;
            SetWindowLong(Handle, -20, GetWindowLong(Handle, -20) | 0x80000 | 0x20);
            RegisterHotKey(Handle, 1, 0x0006, 0x43); RegisterHotKey(Handle, 2, 0x0006, 0x53); RegisterHotKey(Handle, 3, 0x0006, 0x45);
            LoadAppIcon();
            InitializeConfigWatcher();

            tray = new NotifyIcon { Icon=appIcon, Visible=true, Text="Confetti (Ctrl+Shift+C)" };
            var m = new ContextMenu();
            startupMenuItem = new MenuItem("Start on Startup", (s, e)=>ToggleStartupFromTray());
            startupMenuItem.Checked = AppStore.IsStartupEnabled();
            m.MenuItems.Add(startupMenuItem);
            m.MenuItems.Add("Open Config Folder", (s, e)=>OpenConfigFolder());
            m.MenuItems.Add("Reload Config", (s, e)=>ReloadConfig());
            m.MenuItems.Add("-");
            m.MenuItems.Add("Exit", (s, e)=>Application.Exit());
            tray.ContextMenu = m; tray.DoubleClick += (s, e)=>OpenConfigFolder();
            
            timer.Tick += (s, e) => { 
                if (pendingSpawns > 0) {
                    float ticksToSpawn = Math.Max(1, AppStore.Duration * 60f);
                    float toSpawn = AppStore.Count / ticksToSpawn;
                    int actual = (int)Math.Max(1, toSpawn);
                    if (toSpawn < 1 && new Random().NextDouble() > toSpawn) actual = 0;
                    pendingSpawns -= actual;
                    for (int j = 0; j < actual; j++) parts.Add(new Particle(Width, Height));
                }
                for(int i=parts.Count-1; i>=0; i--) if(!parts[i].Update(AppStore.Gravity, AppStore.Wobble, Height)) parts.RemoveAt(i);
                Invalidate();
            };
            timer.Start();
        }

        private void LoadAppIcon() {
            try {
                string iconPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "confetti.ico");
                if (File.Exists(iconPath)) {
                    appIcon = new Icon(iconPath);
                } else {
                    byte[] bytes = Convert.FromBase64String(ICON_BASE64);
                    using (MemoryStream ms = new MemoryStream(bytes)) {
                        using (Bitmap bmp = (Bitmap)Image.FromStream(ms)) {
                            IntPtr hIcon = bmp.GetHicon();
                            try {
                                appIcon = (Icon)Icon.FromHandle(hIcon).Clone();
                            } finally {
                                DestroyIcon(hIcon);
                            }
                        }
                    }
                }
                this.Icon = appIcon;
                if (tray != null) tray.Icon = appIcon;
            } catch {}
        }

        void InitializeConfigWatcher()
        {
            configReloadTimer.Tick += delegate {
                configReloadTimer.Stop();
                ReloadConfig();
            };

            try {
                configWatcher = new FileSystemWatcher(AppStore.ConfigDirectoryPath, Path.GetFileName(AppStore.ConfigFilePath));
                configWatcher.NotifyFilter = NotifyFilters.LastWrite | NotifyFilters.FileName | NotifyFilters.CreationTime;
                FileSystemEventHandler onChange = delegate { QueueConfigReload(); };
                RenamedEventHandler onRename = delegate { QueueConfigReload(); };
                configWatcher.Changed += onChange;
                configWatcher.Created += onChange;
                configWatcher.Renamed += onRename;
                configWatcher.EnableRaisingEvents = true;
            } catch {}
        }

        void QueueConfigReload()
        {
            if (!IsHandleCreated) return;
            try {
                BeginInvoke((MethodInvoker)delegate {
                    configReloadTimer.Stop();
                    configReloadTimer.Start();
                });
            } catch {}
        }

        void ReloadConfig()
        {
            var before = SettingsSnapshot.Capture();
            AppStore.Load();
            var after = SettingsSnapshot.Capture();
            SyncTrayStartupState();
            ApplyLiveSettings(before, after);
        }

        void ToggleStartupFromTray()
        {
            try {
                bool enabled = !AppStore.IsStartupEnabled();
                AppStore.SetStartup(enabled);
                AppStore.Save();
                SyncTrayStartupState();
            } catch {}
        }

        void SyncTrayStartupState()
        {
            if (startupMenuItem != null) startupMenuItem.Checked = AppStore.IsStartupEnabled();
        }

        void OpenConfigFolder()
        {
            try {
                if (!Directory.Exists(AppStore.ConfigDirectoryPath)) Directory.CreateDirectory(AppStore.ConfigDirectoryPath);
                Process.Start("explorer.exe", AppStore.ConfigDirectoryPath);
            } catch {}
        }

        protected override void OnPaint(PaintEventArgs e) {
            e.Graphics.SmoothingMode = SmoothingMode.None; e.Graphics.PixelOffsetMode = PixelOffsetMode.Half;
            PointF[] pts = new PointF[4];
            double toRad = Math.PI / 180.0;
            foreach(var p in parts) {
                double rad = p.Angle * toRad;
                double cos = Math.Cos(rad);
                double sin = Math.Sin(rad);
                float hW = p.W * 0.5f;
                float hH = p.H * 0.5f;

                pts[0] = new PointF((float)(p.X + (-hW * cos - -hH * sin)), (float)(p.Y + (-hW * sin + -hH * cos)));
                pts[1] = new PointF((float)(p.X + (hW * cos - -hH * sin)), (float)(p.Y + (hW * sin + -hH * cos)));
                pts[2] = new PointF((float)(p.X + (hW * cos - hH * sin)), (float)(p.Y + (hW * sin + hH * cos)));
                pts[3] = new PointF((float)(p.X + (-hW * cos - hH * sin)), (float)(p.Y + (-hW * sin + hH * cos)));

                e.Graphics.FillPolygon(Particle.Brushes[p.ColorIndex], pts);
            }
        }
        protected override void WndProc(ref Message m) { 
            if(m.Msg==0x0312) { 
                int id = m.WParam.ToInt32();
                if(id == 1) Fire(); else if(id == 2) OpenConfigFolder(); else if(id == 3) CycleOrigin();
            } 
            base.WndProc(ref m); 
        }
        void Fire() {
            Fire(false);
        }
        void Fire(bool force) {
            if (!force && (DateTime.Now - lastFire).TotalMilliseconds < 300) return;
            if (pendingSpawns > AppStore.Count * 2) return;
            pendingSpawns += AppStore.Count; lastFire = DateTime.Now;
        }
        void ApplyLiveSettings(SettingsSnapshot before, SettingsSnapshot after) {
            if (before == null || after == null) return;
            bool disruptive = Math.Abs(after.Speed - before.Speed) > 0.001f ||
                              Math.Abs(after.Spread - before.Spread) > 0.001f ||
                              Math.Abs(after.Density - before.Density) > 0.001f ||
                              after.Origin != before.Origin;
            if (disruptive) {
                parts.Clear();
            } else {
                for (int i = 0; i < parts.Count; i++) parts[i].ApplySettingsDelta(before, after);
            }
            if (pendingSpawns > after.Count * 2) pendingSpawns = after.Count * 2;
            Invalidate();
        }
        void CycleOrigin() {
            string[] modes = {"sides", "top", "center"};
            int idx = Array.IndexOf(modes, AppStore.Origin);
            AppStore.Origin = modes[(idx + 1) % modes.Length];
            AppStore.Save();
        }
        protected override void OnFormClosed(FormClosedEventArgs e) {
            tray.Visible = false;
            tray.Dispose();
            if (configWatcher != null) configWatcher.Dispose();
            configReloadTimer.Dispose();
            if (appIcon != null) appIcon.Dispose();
            base.OnFormClosed(e);
        }
        [STAThread] static void Main() { AppStore.Load(); bool ok; using(var mx=new Mutex(true,"Confetti_App_Native_V11_Startup",out ok)){ if(!ok)return; Application.EnableVisualStyles(); Application.SetCompatibleTextRenderingDefault(false); Application.Run(new ConfettiMain()); } }

        const string ICON_BASE64 = @"
";
    }
}
